import{_ as i,o,c as t,ae as a}from"./chunks/framework.D4EcyEfM.js";const p=JSON.parse('{"title":"Concepts","description":"","frontmatter":{},"headers":[],"relativePath":"guide/concepts.md","filePath":"guide/concepts.md"}'),r={name:"guide/concepts.md"};function l(c,e,s,d,n,m){return o(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="concepts" tabindex="-1">Concepts <a class="header-anchor" href="#concepts" aria-label="Permalink to &quot;Concepts&quot;">​</a></h1><h2 id="what-is-eidolondb" tabindex="-1">What Is EidolonDB? <a class="header-anchor" href="#what-is-eidolondb" aria-label="Permalink to &quot;What Is EidolonDB?&quot;">​</a></h2><p>EidolonDB is a memory system for AI agents. Instead of only storing embeddings, it extracts candidate memories, classifies them into tiers, deduplicates low-signal data, and runs lifecycle policies to evolve memory over time.</p><h2 id="how-it-differs-from-a-vector-db" tabindex="-1">How It Differs from a Vector DB <a class="header-anchor" href="#how-it-differs-from-a-vector-db" aria-label="Permalink to &quot;How It Differs from a Vector DB&quot;">​</a></h2><p>A vector DB is primarily storage + similarity lookup. EidolonDB adds memory behavior:</p><ul><li>extraction from raw unstructured input</li><li>tiered memory state (<code>short_term</code>, <code>episodic</code>, <code>semantic</code>)</li><li>lifecycle automation (promotion, distillation, expiration, archival)</li><li>hybrid ranking (semantic + recency + importance)</li></ul><h2 id="the-three-tiers" tabindex="-1">The Three Tiers <a class="header-anchor" href="#the-three-tiers" aria-label="Permalink to &quot;The Three Tiers&quot;">​</a></h2><ul><li><code>short_term</code>: immediate, volatile context; decays quickly</li><li><code>episodic</code>: medium-horizon events and decisions</li><li><code>semantic</code>: durable long-term facts and distilled knowledge</li></ul><h2 id="memory-pipeline" tabindex="-1">Memory Pipeline <a class="header-anchor" href="#memory-pipeline" aria-label="Permalink to &quot;Memory Pipeline&quot;">​</a></h2><ol><li>Ingest raw input (<code>POST /ingest</code>)</li><li>Extract candidate memories with LLM</li><li>Classify candidates by memory tier</li><li>Deduplicate against existing memory</li><li>Store accepted memory (if <code>autoStore: true</code>)</li><li>Apply lifecycle rules over time (<code>POST /lifecycle/run</code>)</li></ol>',10)])])}const u=i(r,[["render",l]]);export{p as __pageData,u as default};
